import{_ as e,c as t,o as r,a3 as a}from"./chunks/framework.6s30bTua.js";const g=JSON.parse('{"title":"Performance Metrics","description":"User-Centric Performance Metrics","frontmatter":{"title":"Performance Metrics","description":"User-Centric Performance Metrics"},"headers":[],"relativePath":"Languages/HTML/Performance_Metrics.md","filePath":"Languages/HTML/Performance_Metrics.md","lastUpdated":1667218623000}'),i={name:"Languages/HTML/Performance_Metrics.md"},n=a('<h1 id="performance-metrics" tabindex="-1">Performance Metrics <a class="header-anchor" href="#performance-metrics" aria-label="Permalink to &quot;Performance Metrics&quot;">​</a></h1><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Is it happening?</td><td>Did the navigation start successfully? Has the server responded?</td></tr><tr><td>Is it useful?</td><td>Has enough content rendered that users can engage with it?</td></tr><tr><td>Is it usable?</td><td>Can users interact with the page, or is it busy?</td></tr><tr><td>Is it delightful?</td><td>Are the interactions smooth and natural, free of lag and jank?</td></tr></tbody></table><h2 id="types-of-metrics" tabindex="-1">Types of Metrics <a class="header-anchor" href="#types-of-metrics" aria-label="Permalink to &quot;Types of Metrics&quot;">​</a></h2><ul><li><p><strong>Perceived load speed</strong>: how quickly a page can load and render all of its visual elements to the screen.</p></li><li><p><strong>Load responsiveness</strong>: how quickly a page can load and execute any required JavaScript code in order for components to respond quickly to user interaction</p></li><li><p><strong>Runtime responsiveness</strong>: after page load, how quickly can the page respond to user interaction.</p></li><li><p><strong>Visual stability</strong>: do elements on the page shift in ways that users don&#39;t expect and potentially interfere with their interactions?</p></li><li><p><strong>Smoothness</strong>: do transitions and animations render at a consistent frame rate and flow fluidly from one state to the next?</p></li></ul><h2 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h2><ol><li><p><strong>First Contentful Paint (FCP)</strong>: measures the time from when the page starts loading to when any part of the page&#39;s content is rendered on the screen</p></li><li><p><strong>Largest Contentful Paint (LCP)</strong>: measures the time from when the page starts loading to when the largest text block or image element is rendered on the screen</p></li><li><p><strong>First Input Delay (FID)</strong>: measures the time from when a user first interacts with your site (i.e. when they click a link, tap a button, or use a custom, JavaScript-powered control) to the time when the browser is actually able to respond to that interaction</p></li><li><p><strong>Cumulative Layout Shift (CLS)</strong>: measures the cumulative score of all unexpected layout shifts that occur between when the page starts loading and when its lifecycle state changes to hidden</p></li><li><p><strong>Time to First Byte (TTFB)</strong>: measures the time it takes for the network to respond to a user request with the first byte of a resource</p></li><li><p><strong>Interaction to Next Paint (INP)</strong>: measures the latency of every tap, click, or keyboard interaction made with the page, and-based on the number of interactions-selects the worst interaction latency of the page (or close to the highest) as a single, representative value to describe a page&#39;s overall responsiveness</p></li><li><p><strong>Time to Interactive (TTI)</strong>: measures the time from when the page starts loading to when it&#39;s visually rendered, its initial scripts (if any) have loaded, and it&#39;s capable of reliably responding to user input quickly</p></li><li><p><strong>Total Blocking Time (TBT)</strong>: measures the total amount of time between FCP and TTI where the main thread was blocked for long enough to prevent input responsiveness</p></li></ol><p>Other Matrices:</p><ul><li>User Timing API</li><li>Long Tasks API</li><li>Element Timing API</li><li>Navigation Timing API</li><li>Resource Timing API</li><li>Server timing</li></ul><h2 id="real-user-monitoring-rum" tabindex="-1">Real User Monitoring (RUM) <a class="header-anchor" href="#real-user-monitoring-rum" aria-label="Permalink to &quot;Real User Monitoring (RUM)&quot;">​</a></h2>',9),s=[n];function o(l,c,d,h,p,u){return r(),t("div",null,s)}const f=e(i,[["render",o]]);export{g as __pageData,f as default};
